class TestCryptoDeepOversold(unittest.TestCase):
    def test_fires_on_deep_oversold_both(self):
        stats = {'consecutive_losses': 0}
        fired, reason = heuristic_crypto_deep_oversold(stats, 22.9, 30.9)
        self.assertTrue(fired)
        self.assertIn('22.9', reason)

    def test_no_fire_btc_not_oversold(self):
        stats = {'consecutive_losses': 0}
        fired, _ = heuristic_crypto_deep_oversold(stats, 22.9, 35.0)
        self.assertFalse(fired)

    def test_no_fire_eth_not_oversold(self):
        stats = {'consecutive_losses': 0}
        fired, _ = heuristic_crypto_deep_oversold(stats, 28.0, 30.9)
        self.assertFalse(fired)

    def test_no_fire_on_consecutive_losses(self):
        stats = {'consecutive_losses': 1}
        fired, _ = heuristic_crypto_deep_oversold(stats, 22.9, 30.9)
        self.assertFalse(fired)

    def test_boundary_eth_exactly_25(self):
        stats = {'consecutive_losses': 0}
        fired, _ = heuristic_crypto_deep_oversold(stats, 25.0, 30.9)
        self.assertFalse(fired)
